    if (config_line == NULL || hw_config == NULL || *config_line == '\0') {
        return -1;
    }

    int num_parsed = sscanf(config_line,
                            "cpu_model=%127[^,], memory_mb=%d, disk_path=%255[^,], network_adapter=%63[^,\n]",
                            hw_config->cpu_model,
                            &hw_config->memory_mb,
                            hw_config->disk_path,
                            hw_config->network_adapter);

    if (num_parsed != 4) {
        return -1;
    }

    return 0;
}

